import java.sql.*;
import java.util.ArrayList;
import java.util.List;

public class StudentDAO {
    public void insert(Student s) throws SQLException {
        String sql = "INSERT INTO students (name, branch, marks) VALUES (?, ?, ?)";
        try (Connection conn = JDBCConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql)) {
            ps.setString(1, s.name());
            ps.setString(2, s.branch());
            ps.setInt(3, s.marks());
            ps.executeUpdate();
        }
    }

    public List<Student> findAll() throws SQLException {
        String sql = "SELECT id, name, branch, marks FROM students";
        List<Student> list = new ArrayList<>();
        try (Connection conn = JDBCConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql);
             ResultSet rs = ps.executeQuery()) {
            while (rs.next()) {
                list.add(mapRow(rs));
            }
        }
        return list;
    }

    private Student mapRow(ResultSet rs) throws SQLException {
        return new Student(rs.getInt("id"), rs.getString("name"),
            rs.getString("branch"), rs.getInt("marks"));
    }

    record Student(int id, String name, String branch, int marks) {}
}

