import java.sql.*;
import java.util.ArrayList;
import java.util.List;

public class LibraryDAO {
    public void issueBook(int bookId, String member) throws SQLException {
        Connection conn = JDBCConnection.getConnection();
        try {
            conn.setAutoCommit(false);
            try (PreparedStatement check = conn.prepareStatement(
                    "SELECT available FROM books WHERE id = ?")) {
                check.setInt(1, bookId);
                ResultSet rs = check.executeQuery();
                if (!rs.next() || !rs.getBoolean("available")) {
                    throw new SQLException("Book not available.");
                }
            }
            try (PreparedStatement issue = conn.prepareStatement(
                    "INSERT INTO issues (book_id, member_name, issue_date) VALUES (?, ?, CURDATE())")) {
                issue.setInt(1, bookId);
                issue.setString(2, member);
                issue.executeUpdate();
            }
            try (PreparedStatement upd = conn.prepareStatement(
                    "UPDATE books SET available = FALSE WHERE id = ?")) {
                upd.setInt(1, bookId);
                upd.executeUpdate();
            }
            conn.commit();
        } catch (SQLException e) {
            conn.rollback();
            throw e;
        } finally {
            conn.setAutoCommit(true);
            conn.close();
        }
    }
}

