import java.sql.*;

public class InventoryManagementSystem {
    private final ProductDAO productDAO = new ProductDAO();

    public void adjustStock(int productId, int delta) throws SQLException {
        try (Connection conn = JDBCConnection.getConnection()) {
            conn.setAutoCommit(false);
            int current;
            try (PreparedStatement sel = conn.prepareStatement(
                    "SELECT quantity FROM products WHERE id = ?")) {
                sel.setInt(1, productId);
                ResultSet rs = sel.executeQuery();
                if (!rs.next()) throw new SQLException("Product not found");
                current = rs.getInt("quantity");
            }
            int updated = current + delta;
            if (updated < 0) throw new SQLException("Insufficient stock");
            try (PreparedStatement upd = conn.prepareStatement(
                    "UPDATE products SET quantity = ? WHERE id = ?")) {
                upd.setInt(1, updated);
                upd.setInt(2, productId);
                upd.executeUpdate();
            }
            conn.commit();
            System.out.println("Stock updated. New quantity: " + updated);
        }
    }

    public static void main(String[] args) throws SQLException {
        InventoryManagementSystem app = new InventoryManagementSystem();
        app.adjustStock(1, -2);
        productDAO.findLowStock(10).forEach(System.out::println);
    }

    static ProductDAO productDAO = new ProductDAO();
}

