import java.sql.*;
import java.util.ArrayList;
import java.util.List;

public class HospitalManagementSystem {
    public List<String> viewAppointments() throws SQLException {
        String sql = """
            SELECT p.name AS patient, d.name AS doctor, a.appointment_date, a.status
            FROM appointments a
            JOIN patients p ON a.patient_id = p.id
            JOIN doctors d ON a.doctor_id = d.id
            ORDER BY a.appointment_date
            """;
        List<String> rows = new ArrayList<>();
        try (Connection conn = JDBCConnection.getConnection();
             PreparedStatement ps = conn.prepareStatement(sql);
             ResultSet rs = ps.executeQuery()) {
            while (rs.next()) {
                rows.add(rs.getString("patient") + " | " + rs.getString("doctor")
                    + " | " + rs.getDate("appointment_date") + " | " + rs.getString("status"));
            }
        }
        return rows;
    }

    public static void main(String[] args) throws SQLException {
        HospitalManagementSystem app = new HospitalManagementSystem();
        app.viewAppointments().forEach(System.out::println);
    }
}

